document.querySelectorAll('[data-video-tabs]').forEach(section=>{const player=section.querySelector('[data-player]');section.querySelectorAll('[data-tab]').forEach(btn=>btn.addEventListener('click',()=>{section.querySelectorAll('[data-tab]').forEach(b=>b.classList.remove('active'));btn.classList.add('active');const id=btn.dataset.videoId||'';player.innerHTML=id?`<iframe loading="lazy" src="https://www.youtube.com/embed/${id}" title="Demo robot Alpha Robotics" allowfullscreen></iframe>`:'<div><div class="play"><svg viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg></div><strong>Demo en vídeo</strong></div>';}));});
